#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K;
        scanf("%lld %lld", &N, &K);
        char *s = (char*)malloc(N + 5);
        scanf("%s", s);
        long long zeros = 0, ones = 0;
        for (long long i = 0; i < N; ++i) {
            if (s[i] == '0') zeros++; else ones++;
        }
        long long diff = llabs(zeros - ones);
        long long ans = (diff + K - 1) / K;
        printf("%lld\n", ans);
        free(s);
    }
    return 0;
}

