const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const S = input[idx++];
  let zeros = 0;
  for (let i = 0; i < S.length; ++i) if (S[i] === '0') zeros++;
  const ones = N - zeros;
  const diff = Math.abs(zeros - ones);
  const ans = Math.floor((diff + K - 1) / K);
  results.push(String(ans));
}
console.log(results.join('\n'));
